  `mmr` int NOT NULL,
  `team1_count` tinyint NOT NULL DEFAULT '0',
  `team2_count` tinyint NOT NULL DEFAULT '0',
  `status` enum('queued','cancelled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'queued',
  `claimed_by` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`ticket_id`),
  UNIQUE KEY `party_id` (`party_id`),
  UNIQUE KEY `user_id` (`user_id`),
  KEY `idx_match_tickets_queue_bucket` (`status`,`mode_id`,`mode_variant_id`,`map`,`created_at`),
  CONSTRAINT `fk_mt_party` FOREIGN KEY (`party_id`) REFERENCES `parties` (`party_id`) ON DELETE CASCADE,
  CONSTRAINT `fk_mt_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2269 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
